+namespace {
+/// Compute the Levenshtein edit distance between two strings.
+inline std::size_t levenshtein_distance(const std::string &a, const std::string &b) {
+    std::size_t m = a.size(), n = b.size();
+    std::vector<std::size_t> dp(n + 1);
+    for(std::size_t j = 0; j <= n; ++j)
+        dp[j] = j;
+    for(std::size_t i = 1; i <= m; ++i) {
+        std::size_t prev = dp[0];
+        dp[0] = i;
+        for(std::size_t j = 1; j <= n; ++j) {
+            std::size_t tmp = dp[j];
+            dp[j] = (a[i - 1] == b[j - 1]) ? prev : 1 + std::min({prev, dp[j], dp[j - 1]});
+            prev = tmp;
+        }
+    }
+    return dp[n];
+}
+} // namespace
