+CLI11_INLINE std::string App::_make_extras_suggestion(const std::vector<std::string> &extras) const {
+    // For each extra that looks like a long option, suggest the closest registered long name.
+    std::string suggestion;
+    for(const auto &arg : extras) {
+        if(arg.size() > 2 && arg[0] == '-' && arg[1] == '-') {
+            std::string query = arg.substr(2);
+            std::string best;
+            std::size_t best_dist = std::string::npos;
+            for(const auto &opt : options_) {
+                for(const auto &lname : opt->get_lnames()) {
+                    std::size_t d = levenshtein_distance(query, lname);
+                    if(d < best_dist) {
+                        best_dist = d;
+                        best = lname;
+                    }
+                }
+            }
+            // Only suggest if the distance is small relative to the query length
+            if(!best.empty() && best_dist <= std::max(std::size_t{1}, query.size() / 3 + 1)) {
+                suggestion += "\nDid you mean '--" + best + "'?";
+            }
+        }
+    }
+    return suggestion;
+}
